mapper.select:
SELECT /* 총 세대 수 */ NVL(( SELECT SUM(ac.unit_cnt) FROM apt_complex ac WHERE 1 = 1
), 0) AS totalUnitCnt,
/* 공고 수 */ NVL(( SELECT COUNT(DISTINCT cap.ann_no) FROM center_ann_board_post cap INNER JOIN center_board_instance cbi ON cbi.board_no = cap.board_no INNER JOIN apt_complex ac ON ac.apt_cmplex_no = cbi.apt_cmplex_no WHERE NVL(cap.del_yn, 'N') = 'N' AND TO_CHAR(, 'YYYY') = TO_CHAR(#{year})
), 0) AS announcementCnt,
/* 임대 매물 수 */ NVL(( SELECT COUNT(DISTINCT rl.ho_no) FROM rent_listing rl INNER JOIN apt_detail ad ON ad.ho_no = rl.ho_no INNER JOIN apt_unit au ON au.dong_no = ad.dong_no INNER JOIN apt_complex ac ON ac.apt_cmplex_no = au.apt_cmplex_no LEFT JOIN center_ann_board_post cap2 ON cap2.ann_no = rl.ann_no WHERE TO_CHAR(, 'YYYY') = TO_CHAR(#{year})
), 0) AS rentListingCnt,
/* 계약 완료 매물 수 */ NVL(( SELECT COUNT(DISTINCT rl.ho_no) FROM rent_ctrt rc INNER JOIN rent_listing rl ON rl.rent_lstg_no = rc.rent_lstg_no INNER JOIN apt_detail ad ON ad.ho_no = rl.ho_no INNER JOIN apt_unit au ON au.dong_no = ad.dong_no INNER JOIN apt_complex ac ON ac.apt_cmplex_no = au.apt_cmplex_no LEFT JOIN center_ann_board_post cap2 ON cap2.ann_no = rl.ann_no WHERE rc.ctrt_stts_cd = 'APPROVED' AND TO_CHAR(, 'YYYY') = TO_CHAR(#{year})
), 0) AS approvedContractCnt,
/* 임대계약률 */ NVL(ROUND( NVL(( SELECT COUNT(DISTINCT rl.ho_no) FROM rent_ctrt rc INNER JOIN rent_listing rl ON rl.rent_lstg_no = rc.rent_lstg_no INNER JOIN apt_detail ad ON ad.ho_no = rl.ho_no INNER JOIN apt_unit au ON au.dong_no = ad.dong_no INNER JOIN apt_complex ac ON ac.apt_cmplex_no = au.apt_cmplex_no LEFT JOIN center_ann_board_post cap2 ON cap2.ann_no = rl.ann_no WHERE rc.ctrt_stts_cd = 'APPROVED' AND TO_CHAR(, 'YYYY') = TO_CHAR(#{year})
), 0) / NULLIF(NVL(( SELECT COUNT(DISTINCT rl.ho_no) FROM rent_listing rl INNER JOIN apt_detail ad ON ad.ho_no = rl.ho_no INNER JOIN apt_unit au ON au.dong_no = ad.dong_no INNER JOIN apt_complex ac ON ac.apt_cmplex_no = au.apt_cmplex_no LEFT JOIN center_ann_board_post cap4 ON cap4.ann_no = rl.ann_no WHERE TO_CHAR(, 'YYYY') = TO_CHAR(#{year})
), 0), 0) * 100, 1), 0) AS rentContractRate FROM dual
